from pathlib import Path
from xml.etree import ElementTree as ET

W = "http://schemas.openxmlformats.org/wordprocessingml/2006/main"
XML = "http://www.w3.org/XML/1998/namespace"
ET.register_namespace("w", W)


def w(tag: str) -> str:
    return f"{{{W}}}{tag}"


def make_run(text: str, *, bold: bool = False, color: str | None = None, size: int | None = None) -> ET.Element:
    run = ET.Element(w("r"))
    rpr = ET.SubElement(run, w("rPr"))
    fonts = ET.SubElement(rpr, w("rFonts"))
    for key in ("ascii", "hAnsi", "eastAsia", "cs"):
        fonts.set(w(key), "Times New Roman")
    if bold:
        ET.SubElement(rpr, w("b"))
        ET.SubElement(rpr, w("bCs"))
    if color:
        col = ET.SubElement(rpr, w("color"))
        col.set(w("val"), color)
    if size is not None:
        sz = ET.SubElement(rpr, w("sz"))
        sz.set(w("val"), str(size))
        szcs = ET.SubElement(rpr, w("szCs"))
        szcs.set(w("val"), str(size))
    t = ET.SubElement(run, w("t"))
    if text.startswith(" ") or text.endswith(" "):
        t.set(f"{{{XML}}}space", "preserve")
    t.text = text
    return run


def make_paragraph(text: str, *, style: str | None = None, page_break_before: bool = False, center: bool = False, first_line_twips: int = 708, color: str | None = None, bold: bool = False, size: int | None = None) -> ET.Element:
    p = ET.Element(w("p"))
    ppr = ET.SubElement(p, w("pPr"))
    if style:
        pstyle = ET.SubElement(ppr, w("pStyle"))
        pstyle.set(w("val"), style)
    spacing = ET.SubElement(ppr, w("spacing"))
    spacing.set(w("before"), "0")
    spacing.set(w("after"), "120")
    spacing.set(w("line"), "360")
    spacing.set(w("lineRule"), "auto")
    ind = ET.SubElement(ppr, w("ind"))
    ind.set(w("firstLine"), "0" if style else str(first_line_twips))
    if center:
        jc = ET.SubElement(ppr, w("jc"))
        jc.set(w("val"), "center")
    if page_break_before:
        ET.SubElement(ppr, w("pageBreakBefore"))
    p.append(make_run(text, bold=bold, color=color, size=size))
    return p


def make_placeholder(text: str) -> ET.Element:
    return make_paragraph(text, center=True, first_line_twips=0, color="FF0000", bold=True, size=32)


def make_table(rows: list[list[str]]) -> ET.Element:
    tbl = ET.Element(w("tbl"))
    tbl_pr = ET.SubElement(tbl, w("tblPr"))
    tbl_style = ET.SubElement(tbl_pr, w("tblStyle"))
    tbl_style.set(w("val"), "TableGrid")
    tbl_w = ET.SubElement(tbl_pr, w("tblW"))
    tbl_w.set(w("w"), "0")
    tbl_w.set(w("type"), "auto")
    borders = ET.SubElement(tbl_pr, w("tblBorders"))
    for edge in ("top", "left", "bottom", "right", "insideH", "insideV"):
        el = ET.SubElement(borders, w(edge))
        el.set(w("val"), "single")
        el.set(w("sz"), "8")
        el.set(w("space"), "0")
        el.set(w("color"), "000000")
    grid = ET.SubElement(tbl, w("tblGrid"))
    for width in ("1500", "3200", "3600", "3600"):
        col = ET.SubElement(grid, w("gridCol"))
        col.set(w("w"), width)
    for row_index, row in enumerate(rows):
        tr = ET.SubElement(tbl, w("tr"))
        for cell_text in row:
            tc = ET.SubElement(tr, w("tc"))
            tcpr = ET.SubElement(tc, w("tcPr"))
            tcw = ET.SubElement(tcpr, w("tcW"))
            tcw.set(w("w"), "0")
            tcw.set(w("type"), "auto")
            p = ET.SubElement(tc, w("p"))
            ppr = ET.SubElement(p, w("pPr"))
            spacing = ET.SubElement(ppr, w("spacing"))
            spacing.set(w("before"), "0")
            spacing.set(w("after"), "0")
            spacing.set(w("line"), "240")
            spacing.set(w("lineRule"), "auto")
            p.append(make_run(cell_text, bold=row_index == 0, size=22))
    return tbl


