def main() -> None:
    doc_path = Path(r"docs/documentation/ОТЧЕТ_УП.docx")
    tmp_path = doc_path.with_suffix(".tmp.docx")
    with zipfile.ZipFile(doc_path, "r") as zin:
        root = ET.fromstring(zin.read("word/document.xml"))
        body = root.find(w("body"))
        assert body is not None
        children = list(body)
        sect_pr = copy.deepcopy(children[-1])
        kept = [copy.deepcopy(child) for child in children[:18]]
        body.clear()
        for child in kept:
            body.append(child)
        for child in body_content():
            body.append(child)
        body.append(sect_pr)
        new_xml = ET.tostring(root, encoding="utf-8", xml_declaration=True)
        with zipfile.ZipFile(tmp_path, "w") as zout:
            for item in zin.infolist():
                data = new_xml if item.filename == "word/document.xml" else zin.read(item.filename)
                zout.writestr(item, data)
    tmp_path.replace(doc_path)


if __name__ == "__main__":
    main()
